<!DOCTYPE html><html><head><meta charset="utf-8"><title>Discharge Summary</title><style>body{font-family:sans-serif;color:#111827}.section{border-top:1px solid #111;padding:12px 0}@media print{button{display:none}}</style></head><body><button onclick="window.print()">Print</button><h2>{{ currentFacility()?->name }}</h2><h3>Observation Discharge Summary</h3><p>{{ $discharge->patient?->full_name }} · {{ $discharge->admission?->admission_number }}</p><div class="section"><strong>Dates</strong><p>{{ $discharge->admission?->admitted_at?->format('d M Y H:i') }} - {{ $discharge->discharged_at?->format('d M Y H:i') }}</p></div><div class="section"><strong>Final Diagnosis</strong><p>{{ $discharge->final_diagnosis }}</p></div><div class="section"><strong>Treatment</strong><p>{{ $discharge->treatment_summary }}</p></div><div class="section"><strong>Instructions</strong><p>{{ $discharge->discharge_instructions }}</p></div></body></html>
